import React, { useState, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import '../styles/login.css';

const LoginPage = () => {
  const [role, setRole] = useState(null);
  const [loginMethod, setLoginMethod] = useState('email');
  const [email, setEmail] = useState('expert@cottondisease.com');
  const [password, setPassword] = useState('password');
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [showOtpInput, setShowOtpInput] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  // Get role from session storage on mount
  useEffect(() => {
    const selectedRole = sessionStorage.getItem('selectedRole');
    if (!selectedRole) {
      navigate('/');
      return;
    }
    setRole(selectedRole);
  }, [navigate]);

  // ============= EMAIL LOGIN =============
  const handleEmailLogin = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      // Demo credentials for each role
      const demoCredentials = {
        farmer: { email: 'farmer@cottondisease.com', password: 'password' },
        expert: { email: 'expert@cottondisease.com', password: 'password' },
        admin: { email: 'admin@cottondisease.com', password: 'password' },
      };

      const demo = demoCredentials[role];
      if (email === demo.email && password === demo.password) {
        const result = await login(email, password, role);
        if (result.success) {
          navigate('/dashboard');
        } else {
          setError(result.error || 'Invalid credentials');
        }
      } else {
        setError('Invalid email or password');
      }
    } catch (err) {
      setError('Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  // ============= PHONE + OTP =============
  const handleSendOtp = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const cleanPhone = phone.replace(/\D/g, '');
    if (cleanPhone.length < 10) {
      setError('Please enter a valid 10-digit phone number');
      setLoading(false);
      return;
    }

    try {
      // Simulate OTP send
      console.log(`OTP sent to +91${cleanPhone}`);
      setShowOtpInput(true);
      setError('');
    } catch (err) {
      setError('Failed to send OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    if (otp.length !== 6) {
      setError('Please enter a valid 6-digit OTP');
      setLoading(false);
      return;
    }

    try {
      // Simulate OTP verification
      if (otp === '123456') {
        const cleanPhone = phone.replace(/\D/g, '');
        const result = await login(`+91${cleanPhone}`, otp, role, 'phone');
        if (result.success) {
          navigate('/dashboard');
        } else {
          setError('Verification failed. Please try again.');
        }
      } else {
        setError('Invalid OTP. Please try again.');
      }
    } catch (err) {
      setError('Verification failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  // ============= GOOGLE OAUTH =============
  const handleGoogleLogin = () => {
    setError('');
    setLoading(true);
    try {
      // Simulate Google login
      console.log('Google login initiated for role:', role);
      setTimeout(() => {
        const result = login('user@google.com', 'google_token', role, 'google');
        if (result && result.success) {
          navigate('/dashboard');
        }
        setLoading(false);
      }, 1000);
    } catch (err) {
      setError('Google login failed. Please try again.');
      setLoading(false);
    }
  };

  // ============= UI HELPERS =============
  const getRoleBadge = () => {
    const badges = {
      farmer: { icon: '👨‍🌾', label: 'Farmer', color: '#4CAF50' },
      expert: { icon: '👨‍⚕️', label: 'Expert', color: '#2196F3' },
      admin: { icon: '👨‍💼', label: 'Administrator', color: '#FF9800' },
    };
    return badges[role] || {};
  };

  const getDemoCredentials = () => {
    const creds = {
      farmer: { email: 'farmer@cottondisease.com', password: 'password' },
      expert: { email: 'expert@cottondisease.com', password: 'password' },
      admin: { email: 'admin@cottondisease.com', password: 'password' },
    };
    return creds[role];
  };

  const badge = getRoleBadge();
  const demo = getDemoCredentials();

  return (
    <div className="login-container">
      <div className="login-box">
        <div className="login-logo">
          <h1>🌾 CottonCare AI</h1>
          <p>
            {loginMethod === 'phone' 
              ? 'Login for Farmers' 
              : loginMethod === 'google'
              ? 'Quick Login'
              : 'Expert Verification Platform'}
          </p>
        </div>

        {error && <div className="login-error">{error}</div>}

        {/* LOGIN METHOD TABS */}
        <div className="login-method-tabs">
          <button
            className={`tab-button ${loginMethod === 'email' ? 'active' : ''}`}
            onClick={() => {
              setLoginMethod('email');
              setShowOtpInput(false);
              setIsRegistering(false);
              setError('');
            }}
          >
            📧 Email
          </button>
          <button
            className={`tab-button ${loginMethod === 'phone' ? 'active' : ''}`}
            onClick={() => {
              setLoginMethod('phone');
              setShowOtpInput(false);
              setIsRegistering(false);
              setError('');
            }}
          >
            📱 Phone + OTP
          </button>
          <button
            className={`tab-button ${loginMethod === 'google' ? 'active' : ''}`}
            onClick={() => {
              setLoginMethod('google');
              setError('');
            }}
          >
            🔵 Google
          </button>
        </div>

        {/* ======= EMAIL LOGIN ======= */}
        {loginMethod === 'email' && (
          <form onSubmit={handleEmailLogin}>
            <div className="form-group">
              <label htmlFor="email">Email Address</label>
              <input
                id="email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="expert@example.com"
                required
              />
            </div>

            <div className="form-group">
              <label htmlFor="password">Password</label>
              <input
                id="password"
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter your password"
                required
              />
            </div>

            <button
              type="submit"
              className="login-button"
              disabled={loading}
            >
              {loading ? 'Logging in...' : 'Login'}
            </button>

            <div className="demo-credentials">
              <p><strong>Demo Expert Account:</strong></p>
              <p>Email: expert@cottondisease.com</p>
              <p>Password: password</p>
            </div>
          </form>
        )}

        {/* ======= PHONE + OTP LOGIN/REGISTER ======= */}
        {loginMethod === 'phone' && (
          <form onSubmit={showOtpInput ? handleVerifyOtp : handleSendOtp}>
            {!showOtpInput ? (
              <>
                <div className="form-group">
                  <label htmlFor="phone">Phone Number</label>
                  <div className="phone-input-group">
                    <span className="country-code">+91</span>
                    <input
                      id="phone"
                      type="tel"
                      value={phone}
                      onChange={(e) => setPhone(e.target.value.replace(/\D/g, ''))}
                      placeholder="98765 43210"
                      maxLength="10"
                      required
                    />
                  </div>
                </div>

                <div className="toggle-register">
                  <label>
                    <input
                      type="checkbox"
                      checked={isRegistering}
                      onChange={(e) => setIsRegistering(e.target.checked)}
                    />
                    <span>{isRegistering ? 'Create new account' : 'Existing user'}</span>
                  </label>
                </div>

                <button
                  type="submit"
                  className="login-button"
                  disabled={loading || phone.length < 10}
                >
                  {loading ? 'Sending OTP...' : 'Get OTP'}
                </button>
              </>
            ) : (
              <>
                <div className="otp-message">
                  <p>📱 OTP sent to <strong>+91 {phone}</strong></p>
                  <p className="small-text">Enter the 6-digit code below</p>
                </div>

                <div className="form-group">
                  <label htmlFor="otp">Verification Code</label>
                  <input
                    id="otp"
                    type="text"
                    value={otp}
                    onChange={(e) => setOtp(e.target.value.replace(/\D/g, ''))}
                    placeholder="000000"
                    maxLength="6"
                    required
                    className="otp-input"
                  />
                </div>

                <button
                  type="submit"
                  className="login-button"
                  disabled={loading || otp.length !== 6}
                >
                  {loading ? 'Verifying...' : 'Verify & Login'}
                </button>

                <button
                  type="button"
                  className="resend-button"
                  onClick={() => {
                    setShowOtpInput(false);
                    setOtp('');
                  }}
                  disabled={loading}
                >
                  ← Back to phone number
                </button>
              </>
            )}

            <div className="demo-credentials">
              <p><strong>📱 Demo Phone Number:</strong></p>
              <p>+91 9876543210</p>
              <p className="small-text">Any 6-digit code works in demo</p>
            </div>
          </form>
        )}

        {/* ======= GOOGLE LOGIN ======= */}
        {loginMethod === 'google' && (
          <div className="google-login-container">
            <p className="oauth-description">Sign in with your Google account</p>
            <button
              type="button"
              className="google-login-button"
              onClick={handleGoogleLogin}
              disabled={loading}
            >
              <span className="google-icon">🔵</span>
              {loading ? 'Signing in...' : 'Sign in with Google'}
            </button>

            <div className="oauth-info">
              <p>🔒 Secure OAuth authentication</p>
              <p>We never store your password</p>
            </div>
          </div>
        )}

        <div className="login-info">
          <p>🔐 All authentication methods are secure</p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
